class PrimeHptpCapturePacketsTestMethod(BaseMethod):
    def __init__(self,
                 name,
                 AlignmentLabel=optional,
                 ApplyEndSequence=optional,
                 BypassPort=optional,
                 DataBits=required,
                 DomainRegex=optional,
                 FivrConditionName=optional,
                 FivrConditionPlistParamName=optional,
                 FlowIndex=optional,
                 FlowIndexCallbackName=optional,
                 IdBits=required,
                 InstanceSummaryMode=optional,
                 InvalidPacketTolerance=optional,
                 KeyForSharedStorage=required,
                 LabelOffset=optional,
                 LevelsTc=required,
                 LogLevel=optional,
                 MainPatternRegex=optional,
                 MaskPins=optional,
                 PacketSize=required,
                 Patlist=required,
                 Pins=required,
                 PostInstance=optional,
                 PostPlist=optional,
                 PreInstance=optional,
                 PrePlist=optional,
                 RelayTestConditionName=optional,
                 ReversePacketOutput=optional,
                 Sequence=required,
                 SetPointsPlistMode=optional,
                 SetPointsPlistParamName=optional,
                 SetPointsPostInstance=optional,
                 SetPointsPreInstance=optional,
                 SetPointsRegEx=optional,
                 SoftwareTriggerCallBack=optional,
                 TelemetryLevel=optional,
                 Timeout=optional,
                 TimingsTc=required,
                 TotalCaptureCount=optional,
                 ValidBits=required,
                 ValidFailingPatternsRegex=optional,
                 ValidValues=required,
                 _comment=None,
                 _fitem=None,
                 ):
        """
        Args:
            AlignmentLabel (Optional String): Gets or sets a string that matches to the alignment label contained in functional test content. Label is used to indicate first vector strobing for packet data. Default: None.
            ApplyEndSequence (Optional String): Sets if has to apply the EndSequence at the end of the current instance or not. Default: DISABLED. Options: DISABLED, ENABLED.
            BypassPort (Optional Integer): Port number, provided literally to bypass execution. Use nonnegative to bypass. Default: -1.
            DataBits (Required String): Indexes of bits of packet data used marked as data for output. Default: None.
            DomainRegex (Optional String): Gets or sets a string representing a the regex to use when matching to the domain to use when collecting strobing data from the main pattern. If the regex matches to more than one domain, the first domain that the regex matched to will be used. Default: None.
            FivrConditionName (Optional String): Sets the Fivr Condition to apply. Default: None.
            FivrConditionPlistParamName (Optional String): The name of the parameter in the current instance that holds the plist name. If a FivrCondition is specified, this field must not be empty. Default: None.
            FlowIndex (Optional String): Specify the instance flow index on Dynamic Flows. Default: None.
            FlowIndexCallbackName (Optional String): Flow Index callback function name. in the format of CALLBACKNAME(ARGS). Default: None.
            IdBits (Required String): Indexes of packet data used to determine the sequence of packet data. Default: None.
            InstanceSummaryMode (Optional String): Enable for instance summary information. Default: Disabled. Options: Disabled, Enabled.
            InvalidPacketTolerance (Optional Integer): The maximum allowed invalid cycles when assembling packets. By default, any invalid packets will cause the test method to exit port 2. Default: 0.
            KeyForSharedStorage (Required String): Gets or sets the key to use when inserting the final binary string into shared storage. Default: None.
            LabelOffset (Optional Integer): Gets or sets an integer indicating the offset the alignment label (or from the first vector) where pattern begins strobing for packet data. Default: 0.
            LevelsTc (Required Level): Gets or sets levels test condition to use for functional test execution. Default: None.
            LogLevel (Optional String): Verbosity log level, for console printing of information from code execution. Default: Disabled. Options: Disabled, Enabled.
            MainPatternRegex (Optional String): Gets or sets a string representing a the regex to find the main pattern that is used for packet data retrieval. If the regex matches to more than one domain, the first pattern that the regex matched to will be used. Default: None.
            MaskPins (Optional String): Gets or sets the pins to mask for functional test execution. Default: None.
            PacketSize (Required Integer): The expected size of complete packets. Default: None.
            Patlist (Required Plist): Gets or sets plist to use for functional test execution. Default: None.
            Pins (Required String): Gets or sets list of pins to use for functional test execution. Default: None.
            PostInstance (Optional String): Sets the post-instance callback in the format of CALLBACKNAME(ARGS). Default: None.
            PostPlist (Optional String): Sets the post-plist callback in the format of CALLBACKNAME(ARGS). Default: None.
            PreInstance (Optional String): Sets the pre-instance callback in the format of CALLBACKNAME(ARGS). Default: None.
            PrePlist (Optional String): Sets the pre-plist callback in the format of CALLBACKNAME(ARGS). Default: None.
            RelayTestConditionName (Optional String): The RelayTestCondition to apply. Default: None.
            ReversePacketOutput (Optional String): If true, reverses the bits of the output packets before placing them into SharedStorage. Default: False. Options: True, False.
            Sequence (Required String): Gets or sets a sequence of integer values that will be used to sequence packets in 'Wave'. These values will be checked against the sequence value of each packet. Default: None.
            SetPointsPlistMode (Optional String): Plist Mode to Local or Global. Default: Local. Options: Global, Local.
            SetPointsPlistParamName (Optional String): The name of a param at current instance that hold plist name.If empty setpoints will be applied on all patterns defined in configurations. Default: None.
            SetPointsPostInstance (Optional String): A list of Group names and Set point value to apply after test execution. Default: None.
            SetPointsPreInstance (Optional String): A list of Group names and Set point value to apply before test execution. Default: None.
            SetPointsRegEx (Optional String): The Regular Expression to minimize the patterns in the configurations. Default: None.
            SoftwareTriggerCallBack (Optional String): Callback name to use in softwareTrigger. Note: Only is enabled callback name, the argument is payload of TOSTrigger instruction in pattern. Default: None.
            TelemetryLevel (Optional String): Enable for record detailed test time information. Default: None. Options: None, Debug, Information, Critical.
            Timeout (Optional Integer): The maximum allowed time to innerExecute this instance before exiting out port 0. Default: 0.
            TimingsTc (Required Timing): Gets or sets timing test condition to use for functional test execution. Default: None.
            TotalCaptureCount (Optional Integer): Gets or sets the total amount of failures allowed if using PerCycleFails to generate packets. Ignored otherwise. Default: 1000000.
            ValidBits (Required String): Indexes of packet data used to determine the validity of packet data. Default: None.
            ValidFailingPatternsRegex (Optional String): Gets or sets a string representing a regex to use when filtering patterns that contain packet information. If a pattern fails that doesn't match the defined regex, the test method will exit out of port 2. Default: None.
            ValidValues (Required String): The binary values the valid bits should display to consider the packet data as valid. Default: None.
        """
        self._init(name, locals())
# End of PrimeHptpCapturePacketsTestMethod class definition


